(window.webpackJsonp=window.webpackJsonp||[]).push([[381],{1008:function(r,n){r.exports="\x3c!-- \r\ntitle: 04-权限+读wiki\r\nsort: \r\n--\x3e \r\n\r\n- [ ] 操作权限\r\n- [ ] 读英文文档\r\n- [ ] 挂载u盘\r\n\r\n## 权限\r\n\r\n> 运行不成功，除了命令输错，剩下便是权限问题了。\r\n\r\n## 基础命令\r\n\r\n- id\r\n\r\n  > 显示用户身份\r\n\r\n- chmod\r\n\r\n  ```bash\r\n  chmod 755 [file]\t# -rwxr-xr-x\r\n  chmod +x [file]\t\t# -nnxnnxnnx 所有用户加运行权限，默认为a\r\n  chmod o-w [file]\t# other用户除去write权限\r\n  chmod 777 -R [folder]\t# 递归增加权限\r\n  ```\r\n\r\n- addusr\r\n\r\n  > 新建用户\r\n  >\r\n  > deluser\r\n\r\n- su\r\n\r\n  > 切换用户\r\n\r\n- chown\r\n\r\n  > 更改文件所有者\r\n  >\r\n  > `chown root:users`：文件所有者改成root，用户组改成users\r\n  >\r\n  > `chown root:`：文件所有者改成root，文件用户组也改成root\r\n\r\n- chgrp\r\n\r\n  > 更改用户组所有权\r\n  >\r\n  > 前一个命令不能改文件夹的\r\n\r\n## LInux小技巧\r\n\r\n`Ctrl+A`: 回到开头\r\n\r\n`alias`: 别名\r\n\r\n## vim\r\n\r\n| 命令    | 用法        |\r\n| ------- | ----------- |\r\n| r       | replace     |\r\n| x       | delete      |\r\n| /       | find        |\r\n| v       | visual      |\r\n| shift+v | line visual |\r\n\r\n## 阅读Arch Wiki\r\n\r\n> 为什么有人说Arch是邪教?"}}]);